/// <summary>
/// apply range for sales id
/// </summary>
/// <param name = "_salesId">Range _salesId</param>
/// <returns>Range</returns>
public Range parmSalesId(Range _salesId = salesId)
{
    salesId = _salesId;
    return salesId;
}
